    @Column(name = "from_user_id", nullable = false)
    val fromUserId: String,

    // 좋아요를 받은 사람
    @Column(name = "to_user_id", nullable = false)
    val toUserId: String,

    // 0: LIKE(좋아요), 1: MATCHED(상호 매칭)
    @Column(nullable = false)
